  CONSTRAINT `employees_manager_id_0674f795_fk_employees_id` FOREIGN KEY (`manager_id`) REFERENCES `employees` (`id`),
  CONSTRAINT `employees_position_id_ae4fa2b1_fk_positions_id` FOREIGN KEY (`position_id`) REFERENCES `positions` (`id`),
  CONSTRAINT `employees_user_id_c7f7a3f4_fk_users_id` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`)
