  `approved_at` datetime(6) DEFAULT NULL,
  `rejection_reason` longtext NOT NULL,
  `created_at` datetime(6) NOT NULL,
  `updated_at` datetime(6) NOT NULL,
  `approved_by_id` bigint DEFAULT NULL,
  `employee_id` bigint NOT NULL,
  `leave_type_id` bigint NOT NULL,
  PRIMARY KEY (`id`),
  KEY `leave_requests_approved_by_id_6227f699_fk_employees_id` (`approved_by_id`),
  KEY `leave_requests_employee_id_bb0575f2_fk_employees_id` (`employee_id`),
  KEY `leave_requests_leave_type_id_aa91b26f_fk_leave_types_id` (`leave_type_id`),
  CONSTRAINT `leave_requests_approved_by_id_6227f699_fk_employees_id` FOREIGN KEY (`approved_by_id`) REFERENCES `employees` (`id`),
  CONSTRAINT `leave_requests_employee_id_bb0575f2_fk_employees_id` FOREIGN KEY (`employee_id`) REFERENCES `employees` (`id`),
  CONSTRAINT `leave_requests_leave_type_id_aa91b26f_fk_leave_types_id` FOREIGN KEY (`leave_type_id`) REFERENCES `leave_types` (`id`)
